const payload = $input.first().json;

function safeGet(obj, path, fallback) {
  return path.split('.').reduce((acc, key) => (acc && acc[key] !== undefined) ? acc[key] : fallback, obj);
}

function arrToText(val) {
  if (Array.isArray(val)) return val.join(', ');
  if (typeof val === 'string') return val;
  return JSON.stringify(val);
}

function flattenAnswers(answers) {
  const flat = {};
  for (const [key, val] of Object.entries(answers || {})) {
    if (val && typeof val === 'object' && !Array.isArray(val)) {
      flat[key] = val.label || val.value || JSON.stringify(val);
    } else {
      flat[key] = arrToText(val);
    }
  }
  return flat;
}

const formatted = {
  type: payload.type,
  form_type: payload.form_type || 'sin_form_type',
  status: payload.status || '',
  answers_flat: flattenAnswers(payload.answers),
  ratings_text: (payload.ratings_summary || []).map(r => r.category + ': ' + r.score + '/' + r.max).join('\n'),
  open_texts: (payload.open_text_responses || []).map(o => '[' + o.sentiment + '] ' + o.question_id + ': ' + o.text + ' (tags: ' + o.tags.join(', ') + ')').join('\n'),
  recipient_email: safeGet(payload, 'email_report.recipient_email', ''),
  email_enabled: safeGet(payload, 'email_report.enabled', false),
  email_subject: safeGet(payload, 'email_report.subject', ''),
  email_headline: safeGet(payload, 'email_report.headline', ''),
  email_summary: safeGet(payload, 'email_report.summary', ''),
  email_insights: arrToText(safeGet(payload, 'email_report.insights', [])),
  email_next_steps: arrToText(safeGet(payload, 'email_report.next_steps', [])),
  email_recommended: arrToText(safeGet(payload, 'email_report.recommended_services', [])),
  template_client: safeGet(payload, 'email_report.templates.client', ''),
  template_internal: safeGet(payload, 'email_report.templates.internal', ''),
  llm_provider: safeGet(payload, 'llm_config.provider', 'gpt_nano'),
  llm_model: safeGet(payload, 'llm_config.model', 'gpt-4o-mini'),
  llm_fallback: safeGet(payload, 'llm_config.fallback_provider', 'openrouter_free'),
  system_message: safeGet(payload, 'ai_instructions.system_message', ''),
  survey_name: safeGet(payload, 'metadata.survey_name', ''),
  source: safeGet(payload, 'metadata.source', ''),
  submittedAt: safeGet(payload, 'metadata.submittedAt', ''),
  phoneNumber: safeGet(payload, 'metadata.phoneNumber', ''),
  raw_payload: payload,
};

return [formatted];

const data = $input.first().json;
const answers = data.answers_flat || {};
let priority = 'low';
if (answers.urgencia === 'ya') priority = 'high';
else if (answers.urgencia === '30_dias') priority = 'medium';
const needStr = (answers.necesidad || '').toLowerCase();
const highValue = ['alertas', 'dashboard', 'whatsapp_followup', 'todo'].some(k => needStr.includes(k));
return [{
  ...data,
  case_type: 'CONTACT_INQUIRY',
  priority,
  is_high_value: highValue,
  lead_name: answers.nombre || 'Sin nombre',
  business: answers.negocio || 'Sin negocio',
  sector: answers.tipo_negocio || 'Sin sector',
  email: answers.email || '',
  phone: answers.telefono || data.phoneNumber || '',
  needs: answers.necesidad || '',
  urgency: answers.urgencia || '',
  budget: answers.presupuesto || '',
  description: answers.descripcion || '',
  channel: answers.canal_encuesta || '',
  survey_types: answers.tipo_encuesta || '',
}];

const data = $input.first().json;
const answers = data.answers_flat || {};
const ratings = data.ratings_text || '';
let avgScore = 0;
const scoreMatches = ratings.match(/([0-9]+)\/5/g);
if (scoreMatches) {
  const scores = scoreMatches.map(s => parseInt(s.split('/')[0]));
  avgScore = scores.reduce((a,b) => a+b, 0) / scores.length;
}
const hasAlert = avgScore < 3 || (data.open_texts || '').toLowerCase().includes('negative');
return [{
  ...data,
  case_type: 'SERVICE_FEEDBACK',
  avg_score: avgScore.toFixed(1),
  has_alert: hasAlert,
  service_received: answers.servicio_recibido || '',
  problem_solved: answers.problema_resuelto || '',
  would_recommend: answers.recomendaria || '',
  contact_phone: answers.telefono_contacto || data.phoneNumber || '',
}];

const data = $input.first().json;
const answers = data.answers_flat || {};
return [{
  ...data,
  case_type: 'EVENT_RSVP',
  attendee_name: answers.nombre || 'Sin nombre',
  email: answers.email || '',
  phone: answers.telefono || data.phoneNumber || '',
  attendance_type: answers.tipo_asistencia || '',
  event_name: answers.evento || data.survey_name || 'Evento soul:23',
  topics: answers.temas_interes || '',
  questions: answers.preguntas_previas || '',
  how_found: answers.como_nos_conociste || '',
}];

const data = $input.first().json;
const answers = data.answers_flat || {};
const ratingsText = data.ratings_text || '';
const lowRatings = ratingsText.includes(': 1/5') || ratingsText.includes(': 2/5');
return [{
  ...data,
  case_type: 'STAFF_EVALUATION',
  evaluado: answers.evaluado || answers.nombre || 'Sin nombre',
  evaluador: answers.evaluador || 'Anonimo',
  low_ratings: lowRatings,
  riesgo_rotacion: (answers.riesgo_operativo || '').toLowerCase().includes('rotacion'),
  sobrecarga: (answers.riesgo_operativo || '').toLowerCase().includes('sobrecarga'),
  departamento: answers.departamento || '',
}];

const data = $input.first().json;
const answers = data.answers_flat || {};
const npsScore = parseInt(answers.nps_score) || 0;
let npsCategory = 'passive';
if (npsScore >= 9) npsCategory = 'promoter';
else if (npsScore <= 6) npsCategory = 'detractor';
return [{
  ...data,
  case_type: 'PROJECT_FEEDBACK',
  project_name: answers.proyecto || data.survey_name || 'Proyecto sin nombre',
  nps_score: npsScore,
  nps_category: npsCategory,
  is_detractor: npsCategory === 'detractor',
  is_promoter: npsCategory === 'promoter',
  client_email: answers.email || '',
  delivery_score: answers.calificacion_proyecto || '',
}];

const data = $input.first().json;
const answers = data.answers_flat || {};
const raw = data.raw_payload || {};
const answeredCount = raw.metadata?.answeredCount || 0;
const surveyId = raw.metadata?.surveyId || 'unknown';
return [{
  ...data,
  case_type: 'SURVEY_ABANDONED',
  answered_count: answeredCount,
  survey_id: surveyId,
  reason: raw.metadata?.reason || 'user_navigated_away',
  started_at: raw.metadata?.startedAt || '',
  recovery_possible: !!(answers.email || data.recipient_email),
}];
